  3→/* Toast notifications */
  4→#toast-container {
  5→    position: fixed;
  6→    top: 1rem;
  7→    right: 1rem;
  8→    z-index: 1000;
  9→    display: flex;
 10→    flex-direction: column;
 11→    gap: 0.5rem;
 12→}
