 14→.toast {
 15→    padding: 0.75rem 1.25rem;
 16→    border-radius: 4px;
 17→    color: #fff;
 18→    font-size: 0.9rem;
 19→    animation: toast-in 0.3s ease, toast-out 0.3s ease 3.5s forwards;
 20→    max-width: 400px;
 21→}
 22→
 23→.toast-success { background: var(--accent, #2563eb); }
 24→.toast-error { background: #dc2626; }
 25→.toast-warning { background: #d97706; }
 26→.toast-info { background: #6b7280; }
 27→
 28→@keyframes toast-in {
 29→    from { opacity: 0; transform: translateX(100%); }
 30→    to { opacity: 1; transform: translateX(0); }
 31→}
 32→
 33→@keyframes toast-out {
 34→    from { opacity: 1; }
 35→    to { opacity: 0; }
 36→}
